function parseTitle(raw) {
  const t = (raw || '').replace(/\s*\|\s*LinkedIn\s*$/i, '').trim();
  const d = t.split(/\s+-\s+/);
  if (d.length >= 2) return { name: d[0].trim(), jobTitle: d[1].trim(), company: (d[2] || '').trim() };
  const p = t.split(/\s*\|\s*/);
  if (p.length >= 2) return { name: p[0].trim(), jobTitle: p[1].trim(), company: (p[2] || '').trim() };
  return { name: t, jobTitle: '', company: '' };
}
function scoreKDM(p) {
  const t = (p.job_title || '').toLowerCase();
  const all = t + ' ' + (p.snippet || '').toLowerCase();
  let s = 2;
  if (/\b(manager|lead|principal|senior|business owner|entrepreneur|chef de projet|responsable|chargé)\b/.test(t)) s += 4;
  else if (/\b(vp|vice.president|director|head of|directeur|managing|associé|partner|country manager)\b/.test(t)) s += 3;
  else if (/\b(ceo|co-founder|cofounder|founder|pdg|cto|coo|cpo|chief|president|président|managing director|directeur général|dg|gérant|fondateur)\b/.test(t)) s += 1;
  if (/\b(startup|saas|tech|ia|ai|b2b|scale|venture|fintech|proptech|healthtech|deep.tech|growth|cloud|digital|innovation|software|platform|hardware)\b/.test(all)) s += 2;
  if (/\b(france|paris|belgique|suisse|maroc|morocco|dubai|uae|qatar|oman|singapore|australie|australia|inde|india|canada|london|uk|espagne|spain|indonésie|indonesia|abidjan|casablanca|hong kong)\b/.test(all)) s += 1;
  return Math.min(s, 10);
}
const profiles = [];
const seenLocal = new Set();
for (const item of $input.all()) {
  for (const r of (item.json.organic || [])) {
    const url = (r.link || '').split('?')[0].split('#')[0].toLowerCase().replace(/\/$/, '');
    if (!url.includes('linkedin.com/in/') || url.endsWith('/in/')) continue;
    if (seenLocal.has(url)) continue;
    seenLocal.add(url);
    const { name, jobTitle, company } = parseTitle(r.title || '');
    if (!name) continue;
    profiles.push({ linkedin_url: url, name, job_title: jobTitle, company, snippet: (r.snippet || '').slice(0, 250), persona: 'A', persona_label: 'Key Decision Maker' });
  }
}
return profiles.map(p => ({ json: { ...p, score: scoreKDM(p) } }));

