const staticData = $getWorkflowStaticData('global');
if (!Array.isArray(staticData.seenUrls)) staticData.seenUrls = [];
function normalizeUrl(url) {
  return (url || '').toLowerCase().replace(/^https?:\/\//i, '').replace(/\/$/, '').replace(/[?#].*$/, '').trim();
}
const seenNorm = new Set(staticData.seenUrls.map(normalizeUrl));
const seenThisRun = new Set();
const newA = [];
const newB = [];
for (const item of $input.all()) {
  const p = item.json;
  const norm = normalizeUrl(p.linkedin_url);
  if (!norm || seenThisRun.has(norm) || seenNorm.has(norm)) continue;
  seenThisRun.add(norm);
  if (p.persona === 'A' && newA.length < 15) newA.push(item);
  else if (p.persona === 'B' && newB.length < 15) newB.push(item);
}
const result = [...newA, ...newB];
return result.length > 0 ? result : [{ json: { _empty: true, message: 'Aucun nouveau profil ce jour' } }];

const staticData = $getWorkflowStaticData('global');
if (!Array.isArray(staticData.seenUrls)) staticData.seenUrls = [];
const fixedNote = $node["Config"].json.fixedNote;
const dateStr = new Date().toISOString().split('T')[0];
const newItems = $input.all().filter(item => !item.json._empty);
const newUrls = newItems.map(item => item.json.linkedin_url).filter(Boolean);
staticData.seenUrls = [...staticData.seenUrls, ...newUrls];
if (staticData.seenUrls.length > 5000) staticData.seenUrls = staticData.seenUrls.slice(-5000);
return newItems.map(item => {
  const p = item.json;
  return { json: { batch_date: dateStr, persona: p.persona === 'A' ? 'KDM' : 'Community', score: p.score || 0, nom: p.name, titre: p.job_title, entreprise: p.company, linkedin_url: p.linkedin_url, note_connexion: fixedNote } };
});

const profiles = $input.all().map(i => i.json).filter(p => p.linkedin_url);
const dateStr = new Date().toISOString().split('T')[0];
const personaACount = profiles.filter(p => p.persona === 'KDM').length;
const personaBCount = profiles.filter(p => p.persona === 'Community').length;
const totalProfiles = profiles.length;
const avgScore = totalProfiles > 0 ? (profiles.reduce((s, p) => s + (Number(p.score) || 0), 0) / totalProfiles).toFixed(1) : '0.0';
const q = v => '"' + String(v || '').replace(/"/g, '""') + '"';
const sorted = [...profiles].sort((a, b) => (Number(b.score) || 0) - (Number(a.score) || 0));
const header = 'batch_date,persona,score,nom,titre,entreprise,linkedin_url,note_connexion';
const rows = sorted.map(p => [q(p.batch_date), q(p.persona), p.score || 0, q(p.nom), q(p.titre), q(p.entreprise), p.linkedin_url, q(p.note_connexion)].join(','));
const csv = header + '\n' + rows.join('\n');
const binary = await this.helpers.prepareBinaryData(Buffer.from(csv, 'utf-8'), 'prospects_all_' + dateStr + '.csv', 'text/csv');
return [{ json: { totalProfiles, personaACount, personaBCount, avgScore, dateStr }, binary: { attachment: binary } }];
